+  try {
+    const discovery = await ConfigurationManager.discoverAndLoadConfig();
+    if (discovery) {
+      const { config, projectRoot } = discovery;
+      const executableTargets = ConfigurationManager.getExecutableTargets(config);
+
+      if (executableTargets.length > 0) {
