+      childRef.once('exit', exitHandler);
+      childRef.once('error', exitHandler);
+
+      if (childRef.exitCode !== null || childRef.signalCode) {
+        exitHandler();
+        return;
+      }
+
+      if (!childRef.kill(signal)) {
